import React from 'react';
import { Redirect, Route, Switch } from 'react-router-dom';
import {
  getArticlesNews,
  getTrendingNews,
  getCategoryNews,
} from '../../api/news';
import { HomePage } from '../HomePage';
import { ArticlesPage } from '../ArticlesPage';
import './Main.scss';

export const Main = () => {
  return (
    <div className="Main">
      <Switch>
        <Route path="/articles">
          <ArticlesPage />
        </Route>
        <Route path="/home/:par?">
          <HomePage />
        </Route>
        <Redirect path="/" to="/home" />
      </Switch>
  </div>
  )
};
